function mountain(x1,y1,x2,y2,x3,y3,fill,stroke,snow){
  ctx.beginPath();
  ctx.moveTo(x1,y1);
  ctx.lineTo(x2,y2);
  ctx.lineTo(x3,y3);
  ctx.closePath();
  ctx.fillStyle = fill;
  ctx.fill();
  ctx.strokeStyle = stroke;
  ctx.lineWidth = 2;
  ctx.stroke();

  var sxL = x2 - (x2 - x1) * 0.26;
  var sxR = x2 + (x3 - x2) * 0.26;
  var sy = y2 + (y1 - y2) * 0.24;
  ctx.beginPath();
  ctx.moveTo(x2, y2 + 2);
  ctx.lineTo(sxL, sy);
  ctx.lineTo(sxR, sy);
  ctx.closePath();
  ctx.fillStyle = snow;
  ctx.fill();
}

