for (var i = 0; i < 38; i++) {
  var tx = (i / 37) * w + ((i % 3) - 1) * 6;
  var th = 18 + (i % 7) * 6;
  var tw = 10 + (i % 4) * 2;
  var ty = horizon + 1 + (i % 4) * 2;
  ctx.beginPath();
  ctx.moveTo(tx, ty - th);
  ctx.lineTo(tx - tw, ty);
  ctx.lineTo(tx + tw, ty);
  ctx.closePath();
  ctx.fillStyle = (i % 2 === 0) ? 'rgba(35,255,220,0.16)' : 'rgba(220,90,255,0.14)';
  ctx.fill();
  if (i % 4 === 0) {
    ctx.fillStyle = 'rgba(220,245,255,0.18)';
    ctx.beginPath();
    ctx.moveTo(tx, ty - th);
    ctx.lineTo(tx - tw * 0.45, ty - th * 0.45);
    ctx.lineTo(tx + tw * 0.45, ty - th * 0.45);
    ctx.closePath();
    ctx.fill();
  }
}

