  var r = f.size * 4;
  var glow = ctx.createRadialGradient(f.x, f.y, 0, f.x, f.y, r);
  glow.addColorStop(0, 'hsla(' + Math.floor(f.hue) + ',100%,85%,' + (a * 0.95).toFixed(3) + ')');
  glow.addColorStop(0.35, 'hsla(' + Math.floor(f.hue) + ',100%,68%,' + (a * 0.35).toFixed(3) + ')');
  glow.addColorStop(1, 'hsla(' + Math.floor(f.hue) + ',100%,55%,0)');
  ctx.fillStyle = glow;
  ctx.fillRect(f.x - r, f.y - r, r * 2, r * 2);
  ctx.beginPath();
  ctx.arc(f.x, f.y, f.size * 0.7, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(240,248,255,' + (a * 0.92).toFixed(3) + ')';
  ctx.fill();
}
